  S = empty set
  Q = MIN-PRIORITY-QUEUE(G.V)
  while Q ≠ empty:
    u = EXTRACT-MIN(Q)
    S = S ∪ {u}
    for each v in G.Adj[u]:
      RELAX(u, v, w)

